CREATE OR REPLACE FUNCTION fpa_tel_recrive_status (as_memno char) RETURNS char AS $body$
DECLARE

  ls_recstatus char(1);

BEGIN
  begin
    select	recrieve_status  into STRICT		ls_recstatus
    from		sc_mem_m_member_reg_no_control
    where (membership_no = as_memno );
  exception
  when no_data_found then null;
  when others then CALL spa_dberror('select failed!');
  end;
